+fn bonus_lines_to_text(lines: codec::SerializedLines) -> String {
+    let (lines, _images) = lines.extract_data();
+    let mut text = String::new();
+    for (idx, (_row, line)) in lines.into_iter().enumerate() {
+        if idx > 0 {
+            text.push('\n');
+        }
+        text.push_str(line.as_str().as_ref());
+    }
+    text
